// MARK: - Promo Service

class PromoService {
    static let shared = PromoService()
    
    private var appliedPromoCodes: [String] = []
    private let userDefaults = UserDefaults.standard
    private let appliedPromoCodesKey = "appliedPromoCodes"
    
    private init() {
        appliedPromoCodes = userDefaults.stringArray(forKey: appliedPromoCodesKey) ?? []
    }
    
    func validatePromoCode(_ code: String, discount: Int, completion: @escaping (PromoApplicationResult) -> Void) {
        guard !code.isEmpty else {
            completion(PromoApplicationResult(success: false, message: "Promo code is empty.", appliedDiscount: nil, promoCode: nil))
            return
        }
        
        guard discount > 0 && discount <= 100 else {
            completion(PromoApplicationResult(success: false, message: "Invalid discount percentage. Must be between 1 and 100.", appliedDiscount: nil, promoCode: nil))
            return
        }
        
        guard !appliedPromoCodes.contains(code) else {
            completion(PromoApplicationResult(success: false, message: "Promo code '\(code)' has already been applied to your account.", appliedDiscount: nil, promoCode: code))
            return
        }
        
        // Simulate network validation
        DispatchQueue.global().asyncAfter(deadline: .now() + 1.0) { [weak self] in
            // In production, this would be an API call to validate the promo code server-side
            let isValid = self?.validateCodeFormat(code) ?? false
            
            DispatchQueue.main.async {
                if isValid {
                    self?.applyPromoCode(code, discount: discount, completion: completion)
                } else {
                    completion(PromoApplicationResult(success: false, message: "Promo code '\(code)' is invalid or expired.", appliedDiscount: nil, promoCode: code))
                }
            }
        }
    }
    
    private func validateCodeFormat(_ code: String) -> Bool {
        let codeRegex = "^[A-Za-z0-9]{3,20}$"
        let predicate = NSPredicate(format: "SELF MATCHES %@", codeRegex)
        return predicate.evaluate(with: code)
    }
    
    private func applyPromoCode(_ code: String, discount: Int, completion: @escaping (PromoApplicationResult) -> Void) {
        appliedPromoCodes.append(code)
        userDefaults.set(appliedPromoCodes, forKey: appliedPromoCodesKey)
        
        // Log analytics event
        AnalyticsService.shared.logPromoApplied(code: code, discount: discount)
        
        completion(PromoApplicationResult(
            success: true,
            message: "🎉 Promo code '\(code)' applied successfully! You received a \(discount)% discount.",
            appliedDiscount: discount,
            promoCode: code
        ))
    }
    
    func getAppliedPromoCodes() -> [String] {
        return appliedPromoCodes
    }
    
    func resetPromoCodes() {
        appliedPromoCodes.removeAll()
        userDefaults.removeObject(forKey: appliedPromoCodesKey)
    }
}

