// MARK: - Universal Link Handler

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let supportedHost = "myapp.com"
    private let promoPath = "/promo"
    
    private init() {}
    
    struct PromoLinkParameters {
        let code: String
        let discount: Int
        let source: String?
        let campaignId: String?
    }
    
    func handleUniversalLink(_ url: URL) -> PromoLinkParameters? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            AnalyticsService.shared.logPromoError(error: "Failed to parse URL components", url: url)
            return nil
        }
        
        guard components.host == supportedHost else {
            AnalyticsService.shared.logPromoError(error: "Unsupported host: \(components.host ?? "nil")", url: url)
            return nil
        }
        
        guard components.path == promoPath else {
            AnalyticsService.shared.logPromoError(error: "Unsupported path: \(components.path)", url: url)
            return nil
        }
        
        let queryItems = components.queryItems ?? []
        
        guard let code = queryItems.first(where: { $0.name == "code" })?.value,
              !code.isEmpty else {
            AnalyticsService.shared.logPromoError(error: "Missing or empty promo code", url: url)
            return nil
        }
        
        guard let discountString = queryItems.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString) else {
            AnalyticsService.shared.logPromoError(error: "Missing or invalid discount value", url: url)
            return nil
        }
        
        let source = queryItems.first(where: { $0.name == "source" })?.value
        let campaignId = queryItems.first(where: { $0.name == "campaign_id" })?.value
        
        AnalyticsService.shared.logPromoLinkOpened(code: code, discount: discount, source: source ?? "unknown")
        
        return PromoLinkParameters(code: code, discount: discount, source: source, campaignId: campaignId)
    }
}

