// MARK: - Pending Promo Manager (for handling links when user is not logged in)

class PendingPromoManager {
    static let shared = PendingPromoManager()
    
    private let pendingPromoCodeKey = "pendingPromoCode"
    private let pendingPromoDiscountKey = "pendingPromoDiscount"
    
    private init() {}
    
    func savePendingPromo(code: String, discount: Int) {
        UserDefaults.standard.set(code, forKey: pendingPromoCodeKey)
        UserDefaults.standard.set(discount, forKey: pendingPromoDiscountKey)
    }
    
    func getPendingPromo() -> (code: String, discount: Int)? {
        guard let code = UserDefaults.standard.string(forKey: pendingPromoCodeKey) else {
            return nil
        }
        let discount = UserDefaults.standard.integer(forKey: pendingPromoDiscountKey)
        guard discount > 0 else { return nil }
        return (code, discount)
    }
    
    func clearPendingPromo() {
        UserDefaults.standard.removeObject(forKey: pendingPromoCodeKey)
        UserDefaults.standard.removeObject(forKey: pendingPromoDiscountKey)
    }
}

